    dp[0] = 1;
    dp[1] = s.charAt(0) == '*' ? 9 : (s.charAt(0) == '0' ? 0 : 1);

    for (int i = 2; i <= n; ++i) {
        char c = s.charAt(i - 1);
        char prevC = s.charAt(i - 2);

